mapper.select:
SELECT n.id, n.title, n.category_id as categoryId, nc.name as categoryName, n.type, n.publish_type as publishType, n.publisher_name as publisherName, n.status, n.publish_time as publishTime, n.expire_time as expireTime, n.view_count as viewCount, COALESCE(SUM(CASE WHEN nu.is_read = 1 THEN 1 ELSE 0 END), 0) as readCount, COALESCE(SUM(CASE WHEN nu.is_read = 0 THEN 1 ELSE 0 END), 0) as unreadCount, n.created_at as createdAt FROM notice n LEFT JOIN notice_category nc ON n.category_id = nc.id AND nc.is_deleted = 0 LEFT JOIN notice_user nu ON n.id = nu.notice_id WHERE n.is_deleted = 0
AND n.title LIKE CONCAT('%', #{request.title}, '%')
AND n.category_id = #{request.categoryId}
AND n.type = #{request.type}
AND n.publish_type = #{request.publishType}
AND n.status = #{request.status}
AND n.publish_time >= #{request.startTime}
AND n.publish_time <= #{request.endTime}
GROUP BY n.id ORDER BY n.sort_order DESC, n.publish_time DESC, n.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(DISTINCT n.id)
FROM notice n
WHERE n.is_deleted = 0

    AND n.title LIKE CONCAT('%', #{request.title}, '%')


    AND n.category_id = #{request.categoryId}


    AND n.type = #{request.type}


    AND n.publish_type = #{request.publishType}


    AND n.status = #{request.status}


    AND n.publish_time >= #{request.startTime}


    AND n.publish_time <= #{request.endTime}
